:root {
  --red: #ff0000;
  --black: #000000;
  --white: #ffffff;
}

* { box-sizing: border-box; }

html, body { height: 100%; }

body {
  margin: 0;
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, "Helvetica Neue", Arial, "Apple Color Emoji", "Segoe UI Emoji";
  color: var(--black);
  background-color: var(--white);
  line-height: 1.5;
}

.container {
  max-width: 960px;
  margin: 0 auto;
  padding: 0 1rem;
}

.hero {
  background: var(--black);
  color: var(--white);
  padding: 4rem 0 3rem;
  text-align: center;
}

.hero .subtitle {
  margin-top: 0.5rem;
  color: var(--white);
  opacity: 0.85;
}

h1, h2 {
  margin: 0 0 0.5rem 0;
}

.btn {
  display: inline-block;
  margin-top: 1rem;
  padding: 0.6rem 1.2rem;
  background: var(--red);
  color: var(--white);
  text-decoration: none;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

.services {
  padding: 2rem 0;
  background: var(--white);
  color: var(--black);
}

.service-list {
  list-style: none;
  padding: 0;
  margin: 1rem 0 0 0;
}

.service-list li {
  padding: 0.5rem 0;
  border-bottom: 1px solid var(--black);
}

.contact {
  padding: 2rem 0 3rem;
  background: var(--white);
  color: var(--black);
}

.form-row {
  display: flex;
  flex-direction: column;
  margin-bottom: 1rem;
}

label {
  font-weight: 600;
  margin-bottom: 0.25rem;
}

input, textarea {
  width: 100%;
  padding: 0.6rem;
  border: 1px solid var(--black);
  border-radius: 4px;
  background: var(--white);
  color: var(--black);
}

.footer {
  background: var(--black);
  color: var(--white);
  padding: 1rem 0;
  text-align: center;
}

@media (min-width: 640px) {
  .hero { padding: 6rem 0 4rem; }
}

document.addEventListener('DOMContentLoaded', function () {
  var form = document.getElementById('contact-form');
  var yearEl = document.getElementById('year');

  if (yearEl) {
    yearEl.textContent = String(new Date().getFullYear());
  }

  if (form) {
    form.addEventListener('submit', function (e) {
      e.preventDefault();
      alert('Thank you! Your message has been noted.');
      if (typeof form.reset === 'function') {
        form.reset();
      }
    });
  }
});

{
  "name": "lab-tech-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal single-page landing site for a lab technician with Jest test.",
  "scripts": {
    "test": "jest"
  },
  "devDependencies": {
    "@types/jest": "^29.5.12",
    "jest": "^29.7.0",
    "jest-environment-jsdom": "^29.7.0",
    "ts-jest": "^29.1.1",
    "typescript": "^5.6.3"
  }
}

import fs from 'fs';
import path from 'path';

describe('Landing page', () => {
  it('includes a hero title element', () => {
    const filePath = path.join(__dirname, '..', 'index.html');
    const html = fs.readFileSync(filePath, 'utf8');

    // Use the DOMParser provided by jsdom environment
    const doc = new DOMParser().parseFromString(html, 'text/html');
    const hero = doc.getElementById('hero-title');

    expect(hero).not.toBeNull();
    expect(hero?.textContent?.trim()).not.toBe('');
  });
});
